const stats = $input.item.json;

return [{
  json: {
    success: true,
    timestamp: new Date().toISOString(),
    method: 'TM2 Expanded (150 diseases)',
    summary: {
      totalHerbs: stats.total_herbs,
      totalDiseases: stats.total_diseases,
      totalAssociations: stats.total_associations,
      avgProminence: parseFloat(stats.avg_prominence || 0).toFixed(3),
      avgConfidence: parseFloat(stats.avg_confidence || 0).toFixed(3),
      corpusCoverage: '~90%'
    },
    message: `✅ Agent 0 Complete! Extracted ${stats.total_associations} herb-disease associations from ${stats.total_herbs} herbs and ${stats.total_diseases} diseases using Expanded TM2 (150) + Qdrant + Sarvam AI.`
  }
}];
